/* Aula 02 — modelJs: Console e Debug */

// 1) Logs com rótulo
let a = 10;
let b = 0;
console.log('a:', a);
console.log('b:', b);

// 2) Checagem antes de dividir
if (b === 0) {
  console.error('Divisão por zero!');
} else {
  console.log('resultado:', a / b);
}

// 3) Tabela de dados
const pessoas = [
  { id: 1, nome: 'Ana' },
  { id: 2, nome: 'Bruno' },
  { id: 3, nome: 'Caio' }
];
console.table(pessoas);

// 4) Pausar no ponto exato
// (Abra o DevTools; quando chegar aqui, vai pausar)
debugger;
console.log('Depois do pause');
